import{_ as a,o as t,c as e,a4 as l}from"./chunks/framework.BMymQDdR.js";const g=JSON.parse('{"title":"窗体设计","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Form-Design.md","filePath":"zh/v3/designer/Form-Design.md","lastUpdated":1780630099000}'),i={name:"v3/designer/Form-Design.md"},r=l(`<h1 id="窗体设计" tabindex="-1">窗体设计 <a class="header-anchor" href="#窗体设计" aria-label="Permalink to &quot;窗体设计&quot;">​</a></h1><p>窗体设计是 ENERGY Designer 的核心功能，提供可视化画布用于拖拽放置 UI 组件，支持多窗体并行设计。</p><h2 id="设计画布" tabindex="-1">设计画布 <a class="header-anchor" href="#设计画布" aria-label="Permalink to &quot;设计画布&quot;">​</a></h2><p>设计画布位于设计器中央区域，是放置和编辑 UI 组件的主要工作区。</p><h3 id="画布特性" tabindex="-1">画布特性 <a class="header-anchor" href="#画布特性" aria-label="Permalink to &quot;画布特性&quot;">​</a></h3><ul><li>❌ <strong>网格点</strong> - 画布上显示网格点，辅助组件对齐</li><li><strong>实时预览</strong> - 组件放置后立即显示实际效果</li><li><strong>多标签页</strong> - 支持同时打开多个窗体设计标签页</li></ul><h3 id="画布提示" tabindex="-1">画布提示 <a class="header-anchor" href="#画布提示" aria-label="Permalink to &quot;画布提示&quot;">​</a></h3><p>当没有打开任何项目或窗体时，画布中央会显示快捷操作提示：</p><ul><li>新建项目 (<code>Ctrl+P</code>)</li><li>打开项目 (<code>Ctrl+O</code>)</li><li>新建窗体 (<code>Ctrl+N</code>)</li><li>应用配置 (<code>Ctrl+F11</code>)</li><li>运行 (<code>F9</code>)</li></ul><h2 id="放置组件" tabindex="-1">放置组件 <a class="header-anchor" href="#放置组件" aria-label="Permalink to &quot;放置组件&quot;">​</a></h2><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>在左侧 <strong>组件库</strong> 面板中选择要使用的组件（单击选中，组件图标高亮）</li><li>将鼠标移到设计画布上，鼠标变为放置状态</li><li>在目标位置 <strong>单击</strong> 鼠标左键，组件即被放置</li><li>组件自动获得唯一名称（如 <code>Button1</code>、<code>Label2</code>）</li></ol><h3 id="放置规则" tabindex="-1">放置规则 <a class="header-anchor" href="#放置规则" aria-label="Permalink to &quot;放置规则&quot;">​</a></h3><ul><li>只有接受子控件的容器组件（如 <code>TPanel</code>、<code>TGroupBox</code>、窗体本身）才能作为目标容器</li><li>非可视组件（如 <code>TTimer</code>、<code>TMainMenu</code>）放置后显示默认图标</li><li>放置后自动选中新组件，右侧对象检查器同步显示其属性</li></ul><h3 id="选择工具" tabindex="-1">选择工具 <a class="header-anchor" href="#选择工具" aria-label="Permalink to &quot;选择工具&quot;">​</a></h3><p>组件库中每个分类下都有一个 <strong>选择指针</strong> 工具。选中选择指针后，在画布上点击组件不会放置新组件，而是选中已有组件进行编辑。这是默认的工作状态。</p><h2 id="选择组件" tabindex="-1">选择组件 <a class="header-anchor" href="#选择组件" aria-label="Permalink to &quot;选择组件&quot;">​</a></h2><h3 id="鼠标选择" tabindex="-1">鼠标选择 <a class="header-anchor" href="#鼠标选择" aria-label="Permalink to &quot;鼠标选择&quot;">​</a></h3><p>在设计画布上 <strong>单击</strong> 组件即可选中。选中后：</p><ul><li>组件周围显示 <strong>拖拽控制点</strong>（8 个方向的手柄）</li><li>右侧对象检查器显示该组件的属性和事件</li><li>项目管理器中对应的树节点高亮</li><li>状态栏显示组件名称和位置信息</li></ul><h3 id="点击穿透" tabindex="-1">点击穿透 <a class="header-anchor" href="#点击穿透" aria-label="Permalink to &quot;点击穿透&quot;">​</a></h3><p>当点击容器组件内部的子组件时，会自动选中最上层的子组件，而不是容器本身。</p><h2 id="移动组件" tabindex="-1">移动组件 <a class="header-anchor" href="#移动组件" aria-label="Permalink to &quot;移动组件&quot;">​</a></h2><p>选中组件后，按住鼠标左键 <strong>拖拽</strong> 可移动组件位置。</p><h3 id="拖拽行为" tabindex="-1">拖拽行为 <a class="header-anchor" href="#拖拽行为" aria-label="Permalink to &quot;拖拽行为&quot;">​</a></h3><ul><li>拖拽时实时显示当前位置坐标（X, Y）和尺寸（W, H）</li><li>松开鼠标后自动更新属性列表和 UI 布局文件</li><li>窗体（Form）本身不可移动</li></ul><h3 id="位置提示" tabindex="-1">位置提示 <a class="header-anchor" href="#位置提示" aria-label="Permalink to &quot;位置提示&quot;">​</a></h3><p>拖拽过程中，跟随鼠标会显示一个提示框，实时显示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>X: 100 Y: 50</span></span>
<span class="line"><span>W: 120 H: 30</span></span></code></pre></div><h2 id="调整组件大小" tabindex="-1">调整组件大小 <a class="header-anchor" href="#调整组件大小" aria-label="Permalink to &quot;调整组件大小&quot;">​</a></h2><p>选中组件后，通过 <strong>拖拽控制点</strong> 可调整组件大小。</p><h3 id="控制点说明" tabindex="-1">控制点说明 <a class="header-anchor" href="#控制点说明" aria-label="Permalink to &quot;控制点说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>控制点位置</th><th>鼠标样式</th><th>操作说明</th></tr></thead><tbody><tr><td>左中</td><td>← →</td><td>调整左边距，改变宽度</td></tr><tr><td>上中</td><td>↑ ↓</td><td>调整上边距，改变高度</td></tr><tr><td>右中</td><td>← →</td><td>调整右边距，改变宽度</td></tr><tr><td>下中</td><td>↑ ↓</td><td>调整下边距，改变高度</td></tr><tr><td>左上</td><td>↖ ↘</td><td>同时调整左边距和上边距</td></tr><tr><td>右上</td><td>↗ ↙</td><td>同时调整右边距和上边距</td></tr><tr><td>左下</td><td>↙ ↗</td><td>同时调整左边距和下边距</td></tr><tr><td>右下</td><td>↘ ↖</td><td>同时调整右边距和下边距</td></tr></tbody></table><h3 id="调整行为" tabindex="-1">调整行为 <a class="header-anchor" href="#调整行为" aria-label="Permalink to &quot;调整行为&quot;">​</a></h3><ul><li>拖拽控制点时实时显示位置和尺寸提示</li><li>松开鼠标后自动更新属性列表和 UI 布局文件</li><li>支持从任意方向调整大小</li></ul><h2 id="组件-z-序管理" tabindex="-1">组件 Z 序管理 <a class="header-anchor" href="#组件-z-序管理" aria-label="Permalink to &quot;组件 Z 序管理&quot;">​</a></h2><p>组件的 Z 序（前后层级）可通过项目管理器中的 <strong>右键菜单</strong> 进行调整：</p><ul><li><strong>置顶</strong> - 将组件移到最前面</li><li><strong>置底</strong> - 将组件移到最后面</li><li><strong>上移一层</strong> - 向前移动一层</li><li><strong>下移一层</strong> - 向后移动一层</li></ul><p>调整 Z 序后，组件树中的节点顺序同步更新。</p><h2 id="删除组件" tabindex="-1">删除组件 <a class="header-anchor" href="#删除组件" aria-label="Permalink to &quot;删除组件&quot;">​</a></h2><p>选中组件后，通过以下方式删除：</p><ul><li>在项目管理器中右键组件节点，选择删除</li><li>使用键盘快捷键删除</li></ul><p>删除组件后，对应的组件树节点同步移除。</p><h2 id="多窗体设计" tabindex="-1">多窗体设计 <a class="header-anchor" href="#多窗体设计" aria-label="Permalink to &quot;多窗体设计&quot;">​</a></h2><p>ENERGY Designer 支持同时打开多个窗体进行并行设计。</p><h3 id="标签页切换" tabindex="-1">标签页切换 <a class="header-anchor" href="#标签页切换" aria-label="Permalink to &quot;标签页切换&quot;">​</a></h3><ul><li>点击设计器顶部的窗体标签页切换当前设计的窗体</li><li>切换窗体时，对象检查器自动同步显示对应窗体的属性</li><li>每个窗体标签页可独立显示/隐藏</li></ul><h3 id="窗体属性" tabindex="-1">窗体属性 <a class="header-anchor" href="#窗体属性" aria-label="Permalink to &quot;窗体属性&quot;">​</a></h3><p>选中窗体本身（点击画布空白区域或在组件树中选择窗体根节点），对象检查器显示窗体的属性，如：</p><ul><li><code>Caption</code> - 窗体标题</li><li><code>Width</code> / <code>Height</code> - 窗体尺寸</li><li><code>Position</code> - 窗体初始位置</li><li><code>BorderStyle</code> - 窗体边框样式</li></ul><h2 id="实时自动保存" tabindex="-1">实时自动保存 <a class="header-anchor" href="#实时自动保存" aria-label="Permalink to &quot;实时自动保存&quot;">​</a></h2><p>ENERGY Designer 在设计过程中实时自动保存 UI 布局。每次属性变更、组件增删、位置调整等操作都会自动同步到 <code>.ui</code> 布局文件，无需手动保存。</p>`,52),o=[r];function d(n,h,s,c,u,p){return t(),e("div",null,o)}const q=a(i,[["render",d]]);export{g as __pageData,q as default};
